# Let's compute normalized LCS ratio for each ayah vs query
def lcs_length(a,b):
    # dynamic programming
    n,m=len(a),len(b)
    dp=[0]*(m+1)
    for i in range(1,n+1):
        prev=0
        for j in range(1,m+1):
            temp=dp[j]
            if a[i-1]==b[j-1]:
                dp[j]=prev+1
            else:
                dp[j]=max(dp[j], dp[j-1])
            prev=temp
    return dp[m]

def similarity_lcs(a,b):
    # normalized LCS
    if not a or not b:
        return 0.0
    l=lcs_length(a,b)
    return l / max(len(a), len(b))

